// // This JK flip-flop sets Q to 1 on the rising edge of clk if J is high and K is low, resets Q to 0 if J is low and K is high, and inverts Q if both J and K are high.
module jk_flip_flop (
    input clk,
    input J,
    input K,
    output reg Q
);

    always @(posedge clk) begin
        case ({J, K})
            2'b00: Q <= Q;
            2'b01: Q <= 1'b0;
            2'b10: Q <= 1'b1;
            2'b11: Q <= ~Q;
        endcase
    end

endmodule
